```cpp
  Value *Div, *Rem;
  APInt C1, C2;
  if (!LHS->hasOneUse() || !MatchMul(LHS, Div, C1))
    Div = LHS, C1 = APInt(I.getType()->getScalarSizeInBits(), 1);
  if (!RHS->hasOneUse() || !MatchMul(RHS, Rem, C2))
    Rem = RHS, C2 = APInt(I.getType()->getScalarSizeInBits(), 1);
  if (match(Div, m_IRem(m_Value(), m_Value()))) {
    std::swap(Div, Rem);
    std::swap(C1, C2);
  }
  Value *DivOpV;
  APInt DivOpC;
  if (MatchRem(Rem, X, C0, IsSigned) &&
      MatchDiv(Div, DivOpV, DivOpC, IsSigned) && X == DivOpV && C0 == DivOpC) {
    APInt NewC = C1 - C2 * C0;
    if (!NewC.isZero() && !Rem->hasOneUse())
      return nullptr;
    if (!isGuaranteedNotToBeUndef(X, &AC, &I, &DT))
      return nullptr;
    Value *MulXC2 = Builder.CreateMul(X, ConstantInt::get(X->getType(), C2));
    if (NewC.isZero())
      return MulXC2;
    return Builder.CreateAdd(
        Builder.CreateMul(Div, ConstantInt::get(X->getType(), NewC)), MulXC2);
  }

  // Check for udiv and urem by power of 2: (x >> c) + (x & (2^c - 1))
  if (match(LHS, m_LShr(m_Value(X), m_APInt(C1))) &&
      match(RHS, m_And(m_Specific(X), m_APInt(C2))) &&
      C1.isPowerOf2() && C2 == (C1.zextOrSelf(C2.getBitWidth()) - 1)) {
    // Prove that no overflow can occur: high part (LHS) and low part (RHS) don't overlap
    unsigned ShAmt = C1.logBase2();
    // The low part uses bottom ShAmt bits, the high part has zeros in bottom ShAmt bits
    // So their sum cannot overflow (add nuw nsw)
    I.setIsExact(true);
    I.setHasNoSignedWrap(false);
    I.setHasNoUnsignedWrap(true);
    return &I;
  }

  return nullptr;
